                except OSError as e:
                    print(f"Error deleting file: {item_path} - {e}")
    except FileNotFoundError:
        print(f"Directory not found: {dir_path}")

# Start the cleanup process
try:
    cleanup_directory(root_dir)
except Exception as e:
    print(f"An error occurred: {e}")
